// Generate simulated EHR and billing data
const claims = [];

// Sample data pools
const firstNames = ['John', 'Mary', 'Robert', 'Patricia', 'Michael', 'Jennifer', 'William', 'Linda', 'David', 'Barbara'];
const lastNames = ['Smith', 'Johnson', 'Williams', 'Brown', 'Jones', 'Garcia', 'Miller', 'Davis', 'Rodriguez', 'Martinez'];
const diagnosisCodes = [
  { code: 'E11.9', description: 'Type 2 diabetes mellitus without complications' },
  { code: 'I10', description: 'Essential (primary) hypertension' },
  { code: 'J44.9', description: 'Chronic obstructive pulmonary disease, unspecified' },
  { code: 'M79.3', description: 'Panniculitis, unspecified' },
  { code: 'K21.9', description: 'Gastro-esophageal reflux disease without esophagitis' },
  { code: 'F41.9', description: 'Anxiety disorder, unspecified' },
  { code: 'M25.561', description: 'Pain in right knee' },
  { code: 'R51', description: 'Headache' }
];
const procedureCodes = [
  { code: '99213', description: 'Office visit, established patient, level 3', amount: 150 },
  { code: '99214', description: 'Office visit, established patient, level 4', amount: 200 },
  { code: '99203', description: 'Office visit, new patient, level 3', amount: 180 },
  { code: '80053', description: 'Comprehensive metabolic panel', amount: 75 },
  { code: '85025', description: 'Complete blood count', amount: 45 },
  { code: '93000', description: 'Electrocardiogram', amount: 120 },
  { code: '71045', description: 'Chest X-ray', amount: 95 },
  { code: '36415', description: 'Venipuncture', amount: 25 }
];
const insuranceProviders = [
  { name: 'Blue Cross Blue Shield', payerId: 'BCBS001' },
  { name: 'UnitedHealthcare', payerId: 'UHC002' },
  { name: 'Aetna', payerId: 'AET003' },
  { name: 'Cigna', payerId: 'CIG004' },
  { name: 'Humana', payerId: 'HUM005' },
  { name: 'Medicare', payerId: 'MED006' },
  { name: 'Medicaid', payerId: 'MCAID007' }
];
const claimStatuses = ['pending', 'submitted', 'approved', 'denied', 'appealed'];

// Generate 10 sample claims
for (let i = 1; i <= 10; i++) {
  const firstName = firstNames[Math.floor(Math.random() * firstNames.length)];
  const lastName = lastNames[Math.floor(Math.random() * lastNames.length)];
  const diagnosis = diagnosisCodes[Math.floor(Math.random() * diagnosisCodes.length)];
  const procedure = procedureCodes[Math.floor(Math.random() * procedureCodes.length)];
  const insurance = insuranceProviders[Math.floor(Math.random() * insuranceProviders.length)];
  const status = claimStatuses[Math.floor(Math.random() * claimStatuses.length)];

  // Generate random dates
  const serviceDate = new Date(2024, Math.floor(Math.random() * 12), Math.floor(Math.random() * 28) + 1);
  const submissionDate = new Date(serviceDate.getTime() + (Math.random() * 14 * 24 * 60 * 60 * 1000)); // 0-14 days after service

  // Calculate amounts
  const billedAmount = procedure.amount;
  const allowedAmount = billedAmount * (0.7 + Math.random() * 0.2); // 70-90% of billed
  const patientResponsibility = allowedAmount * (0.1 + Math.random() * 0.2); // 10-30% patient responsibility
  const insurancePayment = allowedAmount - patientResponsibility;

  claims.push({
    claimId: `CLM-2024-${String(i).padStart(6, '0')}`,
    patientDemographics: {
      patientId: `PAT-${String(1000 + i).padStart(6, '0')}`,
      firstName: firstName,
      lastName: lastName,
      dateOfBirth: new Date(1940 + Math.floor(Math.random() * 60), Math.floor(Math.random() * 12), Math.floor(Math.random() * 28) + 1).toISOString().split('T')[0],
      gender: Math.random() > 0.5 ? 'M' : 'F',
      address: `${Math.floor(Math.random() * 9999) + 1} Main St`,
      city: 'Springfield',
      state: 'IL',
      zipCode: String(60000 + Math.floor(Math.random() * 1000))
    },
    diagnosisInfo: {
      primaryDiagnosisCode: diagnosis.code,
      diagnosisDescription: diagnosis.description,
      diagnosisDate: serviceDate.toISOString().split('T')[0]
    },
    procedureInfo: {
      procedureCode: procedure.code,
      procedureDescription: procedure.description,
      serviceDate: serviceDate.toISOString().split('T')[0],
      providerId: `PRV-${String(100 + Math.floor(Math.random() * 50)).padStart(5, '0')}`,
      providerName: 'Springfield Medical Center'
    },
    billingInfo: {
      billedAmount: Math.round(billedAmount * 100) / 100,
      allowedAmount: Math.round(allowedAmount * 100) / 100,
      insurancePayment: Math.round(insurancePayment * 100) / 100,
      patientResponsibility: Math.round(patientResponsibility * 100) / 100,
      currency: 'USD'
    },
    insuranceInfo: {
      insuranceProvider: insurance.name,
      payerId: insurance.payerId,
      policyNumber: `POL-${String(Math.floor(Math.random() * 1000000)).padStart(8, '0')}`,
      groupNumber: `GRP-${String(Math.floor(Math.random() * 10000)).padStart(6, '0')}`,
      coverageType: Math.random() > 0.3 ? 'primary' : 'secondary'
    },
    claimStatus: {
      status: status,
      submissionDate: submissionDate.toISOString().split('T')[0],
      lastUpdated: new Date().toISOString().split('T')[0],
      denialReason: status === 'denied' ? ['Invalid diagnosis code', 'Missing documentation', 'Non-covered service', 'Authorization required'][Math.floor(Math.random() * 4)] : null,
      riskLevel: ['low', 'medium', 'high'][Math.floor(Math.random() * 3)],
      complianceFlag: Math.random() > 0.8 ? true : false
    }
  });
}

return claims.map(claim => ({ json: claim }));

