parameters.jsCode:
// Calculate Revenue Cycle Metrics
const items = $input.all();

// Initialize counters
let totalClaims = 0;
let deniedClaims = 0;
let totalClaimValue = 0;
let complianceIssues = 0;
let escalations = 0;
let processingTimes = [];

// Process each item
for (const item of items) {
  const data = item.json;

  // Count total claims
  if (data.claimId || data.claim_id) {
    totalClaims++;
  }

  // Count denials
  if (data.status === 'denied' || data.denial_detected === true || data.isDenied === true) {
    deniedClaims++;
  }

  // Sum claim values
  if (data.claimAmount || data.claim_amount || data.amount) {
    totalClaimValue += parseFloat(data.claimAmount || data.claim_amount || data.amount || 0);
  }

  // Count compliance issues
  if (data.complianceFlag === true || data.compliance_flag === true || data.hasComplianceIssue === true) {
    complianceIssues++;
  }

  // Count escalations
  if (data.escalated === true || data.requiresEscalation === true) {
    escalations++;
  }

  // Collect processing times
  if (data.processingTime || data.processing_time) {
    processingTimes.push(parseFloat(data.processingTime || data.processing_time));
  }
}

// Calculate metrics
const denialRate = totalClaims > 0 ? (deniedClaims / totalClaims * 100).toFixed(2) : 0;
const averageClaimValue = totalClaims > 0 ? (totalClaimValue / totalClaims).toFixed(2) : 0;
const complianceScore = totalClaims > 0 ? ((totalClaims - complianceIssues) / totalClaims * 100).toFixed(2) : 100;
const escalationRate = totalClaims > 0 ? (escalations / totalClaims * 100).toFixed(2) : 0;
const averageProcessingTime = processingTimes.length > 0 
  ? (processingTimes.reduce((a, b) => a + b, 0) / processingTimes.length).toFixed(2) 
  : 0;

// Return metrics
return [
  {
    json: {
      metrics: {
        totalClaimsProcessed: totalClaims,
        deniedClaims: deniedClaims,
        denialRate: parseFloat(denialRate),
        totalClaimValue: parseFloat(totalClaimValue.toFixed(2)),
        averageClaimValue: parseFloat(averageClaimValue),
        complianceScore: parseFloat(complianceScore),
        complianceIssues: complianceIssues,
        escalations: escalations,
        escalationRate: parseFloat(escalationRate),
        averageProcessingTime: parseFloat(averageProcessingTime),
        timestamp: new Date().toISOString()
      },
      summary: {
        message: `Processed ${totalClaims} claims with ${denialRate}% denial rate and ${complianceScore}% compliance score`,
        totalRevenue: parseFloat(totalClaimValue.toFixed(2)),
        performanceStatus: denialRate < 5 ? 'Excellent' : denialRate < 10 ? 'Good' : denialRate < 15 ? 'Fair' : 'Needs Improvement'
      }
    }
  }
];
